WordTree={}function WordTree:InitTree(a)local b={}setmetatable(b,self)self.__index=self;b.tree={code=0,str='',isEnd=false,childs={},id=0}b.count=0;for c=1,#a do b:AddWord({s=a[c].s,id=a[c].id})end;return b end;function WordTree:AddWord(d)local e=d.s;if not e or e==''then return end;local f=self.tree;for c=1,Tools.GetStringLength(e)do local g=Tools.UTF8Sub(e,c,1)if not f.childs[g]then local h={}h={}h.code=Tools.utf8ToNum(g)h.str=Tools.UTF8Sub(e,1,c)h.isEnd=false;h.childs={}h.id=0;self.count=self.count+1;f.childs[g]=h end;f=f.childs[g]end;f.isEnd=true;f.id=d.id end;function WordTree:AddExtraWord(e)if self:Test(e)then return true end;if self.count>100000 then return false end;self:AddWord(e)return true end;function WordTree:RemoveExtraWord(e)local f=self.tree;for i=1,Tools.GetStringLength(e)do local j=Tools.utf8ToNum(Tools.UTF8Sub(e,i,1))if f.childs[j]then f=f.childs[j]else return end end;f.isEnd=false end;function WordTree:TestZixulie(e)local k={}table.insert(k,self.tree)local l={}for c=1,Tools.GetStringLength(e)do local m=Tools.UTF8Sub(e,c,1)local n=#k;for i=1,n do local o=k[i]local p=o.str==''or l[o.str]+13>=c;if o.childs and o.childs[m]then local q=o.childs[m]if p then if q.isEnd then return{s=q.str,id=q.id}end;if not l[q.str]then table.insert(k,q)end;l[q.str]=c end end end end;return nil end;function WordTree:TestZichuan(e)local k={}table.insert(k,self.tree)local r=0;for c=1,Tools.GetStringLength(e)do local m=Tools.UTF8Sub(e,c,1)local n=#k;local s={}table.insert(s,self.tree)for i=1,n do local o=k[i]r=r+1;if o.childs and o.childs[m]then local q=o.childs[m]if q.isEnd then return{s=q.str,id=q.id}end;table.insert(s,q)end end;k=s end;return nil end;return WordTree